{"code": "import json

# Load funding data
with open('storage/query_result_6.json', 'r') as f:
    funding_records = json.load(f)

# Get projects with funding > $50,000
high_funding_set = set()
for rec in funding_records:
    if int(rec['Amount']) > 50000:
        high_funding_set.add(rec['Project_Name'].lower().strip())

# Load civic documents
with open('storage/query_result_10.json', 'r') as f:
    civic_docs = json.load(f)

# Count matches
count = 0

for doc in civic_docs:
    text = doc.get('text', '')

    # Find design capital projects section
    start = text.find('Capital Improvement Projects (Design)')
    if start < 0:
        continue

    # Find where the section ends
    end = text.find('Capital Improvement Projects (Construction)', start)
    if end < 0:
        end = text.find('Capital Improvement Projects (Not Started)', start)
    if end < 0:
        end = start + 6000

    section = text[start:end]
    lines = section.split('\n')

    for line in lines:
        line = line.strip()
        # Simple heuristic for project names
        if len(line) > 15 and not line.startswith('(') and not line.isupper():
            if 'Updates:' not in line and 'Schedule:' not in line and 'Page' not in line:
                # Check if funded
                line_lower = line.lower()
                for funded in high_funding_set:
                    if funded in line_lower or line_lower in funded:
                        count += 1
                        break

print('__RESULT__:')
print(json.dumps({'count': count}))"}

